components.customConditional:
const UserDetails = JSON.parse(localStorage.getItem("UserDetails"));
const groups = UserDetails ? UserDetails["groups"] : [];
const isReviewer = groups.includes("/formsflow/formsflow-reviewer");
const status = data.applicationStatus;
if ((isReviewer && status === "New") || status === "Reviewed" || status === "Completed") {
  show = true;
}
else {
  show = false;
};

const status = data.applicationStatus;
if (status === 'Reviewed' || status === 'Completed') {
  show = false;
} else {
  show = true;
}

components.custom:
const submissionId = form.submission._id || form._submission._id;
let projectUrl = form.formio.projectUrl;
if (projectUrl.indexOf('/form-io') === -1 && projectUrl.indexOf('/formio') === -1) {
  projectUrl = projectUrl + '/formio';
}
Formio.setBaseUrl(projectUrl);
const formRelativePath = '/form/' + form.formio.formId;
const submissionObj = {
  _id: submissionId,
  data: form.submission.data
};
const formio = new Formio(formRelativePath);
formio.saveSubmission(submissionObj).then(result => {
  console.log('Review saved:', result);
  form.emit('customEvent', {
    type: "actionComplete",
    component: component
  });
}).catch(error => {
  console.error('Error saving submission:', error);
});

components.customConditional:
switch(data.applicationStatus) {
  case "New":
  case "Reviewed":
  case "Completed":
    show = false;
    break;
  default: show = true;
};
